const raw = $input.item.json;
const d = raw.body || raw;
return { json: {
  lead_id: d.lead_id || '',
  company_id: d.company_id || '',
  company_name: d.company_name || '',
  ico: d.ico || '',
  found: false,
  domain: '',
  source: ''
} };

const BLACKLISTED = new Set(['seznam.cz','centrum.cz','atlas.cz','volny.cz','tiscali.cz','o2.cz','vodafone.cz','t-mobile.cz','upc.cz','czfree.net','gmail.com','yahoo.com','hotmail.com','outlook.com','protonmail.com','icloud.com','mail.com','zoho.com','aol.com','gmx.com','gmx.net','yandex.com','tutanota.com','live.com','msn.com','post.cz','email.cz','facebook.com','twitter.com','x.com','linkedin.com','instagram.com','youtube.com','tiktok.com','pinterest.com','reddit.com','threads.net','google.com','google.cz','bing.com','duckduckgo.com','wikipedia.org','wikipedie.cz','firmy.cz','kurzy.cz','rejstrik.penize.cz','or.justice.cz','justice.cz','rzp.cz','ares.gov.cz','hbi.cz','detail.cz','databaze-firem.cz','github.com','gitlab.com','medium.com','wordpress.com','blogspot.com','wix.com','squarespace.com','webnode.cz','amazon.com','ebay.com','alibaba.com','aliexpress.com','apple.com','microsoft.com','cloudflare.com','mapy.cz','idnes.cz','novinky.cz','aktualne.cz','heureka.cz','zbozi.cz','slevomat.cz']);
function isBlacklisted(d) { if (!d) return true; if (BLACKLISTED.has(d)) return true; const p = d.split('.'); if (p.length > 2 && BLACKLISTED.has(p.slice(-2).join('.'))) return true; return false; }
const be = $input.item.json || {};
const prev = $('Extract Input').first().json;
// Handle ARES error responses (404, rate limit, etc.)
if (be.error || be.kod === 'NENALEZENO') {
  return { json: { ...prev, found: false } };
}
let website = '';
if (be.www) website = be.www;
else if (be.sidlo && be.sidlo.www) website = be.sidlo.www;

if (!website) {
  return { json: { ...prev, found: false } };
}

let domain = website.replace(/^https?:\/\//i, '').replace(/^www\./i, '').split(/[\/?#]/)[0].trim().toLowerCase();
if (!domain || !/^[a-z0-9.-]+\.[a-z]{2,}$/.test(domain)) {
  return { json: { ...prev, found: false } };
}

if (isBlacklisted(domain)) {
  return { json: { ...prev, found: false } };
}

return { json: { ...prev, found: true, domain: domain, source: 'ares' } };

const prev = $('Extract Input').first().json;
function stripDiacritics(s) {
  return s.normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase();
}
let raw = prev.company_name || '';
// Strip domain extensions from company names like 'Alza.cz a.s.' or 'Kiwi.com s.r.o.'
raw = raw.replace(/\.(cz|com|eu|sk|net|org)\b/gi, '');
// Strip all Czech legal suffixes (with optional spaces/dots)
raw = raw.replace(/,?\s*\b(s\.?\s*r\.?\s*o\.?|a\.?\s*s\.?|spol\.?\s*s\s*r\.?\s*o\.?|v\.?\s*o\.?\s*s\.?|k\.?\s*s\.?|s\.?\s*p\.?|z\.?\s*s\.?|z\.?\s*u\.?|o\.?\s*p\.?\s*s\.?|s\.?\s*e\.?|druzstvo|narodni\s*podnik|organizacni\s*slozka)\b\.?/gi, '');
raw = raw.replace(/,\s*$/, '').trim();
// Strip geographic/industry qualifiers that inflate the name
raw = raw.replace(/\b(ceska\s*republika|czech\s*republic|cr|international|baumarkt|cash\s*&\s*carry|pojistovna|pojistovni|banka|lekarna|group|investment)\b/gi, '').trim();
raw = raw.replace(/\s+/g, ' ').trim();
const stripped = stripDiacritics(raw);
// Generate candidates
const alphaOnly = stripped.replace(/[^a-z0-9]/g, '').trim();
const words = stripped.replace(/[^a-z0-9\s-]/g, '').trim().split(/\s+/).filter(w => w.length > 0);
const hyphenated = words.length >= 2 ? words.join('-') : '';
// Also try first significant word alone (catches Lidl, Kaufland, Vodafone, etc.)
const firstWord = words.length >= 2 && words[0].length >= 3 ? words[0] : '';
if (!alphaOnly || alphaOnly.length < 2 || /^[0-9]+$/.test(alphaOnly)) {
  return { json: { ...prev, found: false, _dns_candidates: [] } };
}
// Build best 2 candidates for parallel probing
let candidates;
if (alphaOnly.length > 25 && firstWord) {
  // Full name too long — try first word instead
  candidates = [firstWord + '.cz', firstWord + '.com'];
} else if (alphaOnly.length > 25) {
  return { json: { ...prev, found: false, _dns_candidates: [] } };
} else if (firstWord && firstWord !== alphaOnly && words.length >= 2) {
  // Multi-word: try full name .cz and first word .cz
  candidates = [alphaOnly + '.cz', firstWord + '.cz'];
} else if (hyphenated && hyphenated !== alphaOnly) {
  candidates = [alphaOnly + '.cz', hyphenated + '.cz'];
} else {
  candidates = [alphaOnly + '.cz', alphaOnly + '.com'];
}
return { json: { ...prev, _dns_candidates: candidates, _dns_index: 0 } };

const BLACKLISTED = new Set(['seznam.cz','centrum.cz','atlas.cz','volny.cz','tiscali.cz','o2.cz','vodafone.cz','t-mobile.cz','upc.cz','czfree.net','gmail.com','yahoo.com','hotmail.com','outlook.com','protonmail.com','icloud.com','mail.com','zoho.com','aol.com','gmx.com','gmx.net','yandex.com','tutanota.com','live.com','msn.com','post.cz','email.cz','facebook.com','twitter.com','x.com','linkedin.com','instagram.com','youtube.com','tiktok.com','pinterest.com','reddit.com','threads.net','google.com','google.cz','bing.com','duckduckgo.com','wikipedia.org','wikipedie.cz','firmy.cz','kurzy.cz','rejstrik.penize.cz','or.justice.cz','justice.cz','rzp.cz','ares.gov.cz','hbi.cz','detail.cz','databaze-firem.cz','github.com','gitlab.com','medium.com','wordpress.com','blogspot.com','wix.com','squarespace.com','webnode.cz','amazon.com','ebay.com','alibaba.com','aliexpress.com','apple.com','microsoft.com','cloudflare.com','mapy.cz','idnes.cz','novinky.cz','aktualne.cz','heureka.cz','zbozi.cz','slevomat.cz']);
function isBlacklisted(d) { if (!d) return true; if (BLACKLISTED.has(d)) return true; const p = d.split('.'); if (p.length > 2 && BLACKLISTED.has(p.slice(-2).join('.'))) return true; return false; }
const prev = $('Generate DNS Candidates').first().json;
const candidates = prev._dns_candidates || [];
const results = $input.all().map(i => i.json);

// onError:continueRegularOutput wraps errors as { error: { message: '403 - ...' } }
// Extract status from statusCode field or from error message prefix
function extractStatus(r) {
  if (!r) return 0;
  if (typeof r.statusCode === 'number') return r.statusCode;
  if (r.error && r.error.message) {
    const m = r.error.message.match(/^(\d{3})\s*-/);
    if (m) return parseInt(m[1]);
    return 0;
  }
  // No error + has data = successful request (responseFormat:text returns { data: '...' })
  if (r.data !== undefined && r.data !== '') return 200;
  return 0;
}
const czStatus = extractStatus(results[0]);
const comStatus = extractStatus(results[1]);

// Accept 2xx/3xx AND 403 (Cloudflare/WAF = domain exists). Reject 404/5xx/0 (no domain)
function isAlive(status) { return (status >= 200 && status < 400) || status === 403; }
if (isAlive(czStatus) && candidates[0] && !isBlacklisted(candidates[0])) {
  return [{ json: { lead_id: prev.lead_id, company_id: prev.company_id, company_name: prev.company_name, ico: prev.ico, found: true, domain: candidates[0], source: 'dns' } }];
}
if (isAlive(comStatus) && candidates[1] && !isBlacklisted(candidates[1])) {
  return [{ json: { lead_id: prev.lead_id, company_id: prev.company_id, company_name: prev.company_name, ico: prev.ico, found: true, domain: candidates[1], source: 'dns' } }];
}

return [{ json: { lead_id: prev.lead_id, company_id: prev.company_id, company_name: prev.company_name, ico: prev.ico, found: false, domain: '', source: '' } }];

const prev = $('Extract Input').first().json;
const searchQuery = encodeURIComponent(prev.company_name + ' website');
return { json: { ...prev, _ddg_url: 'https://html.duckduckgo.com/html/?q=' + searchQuery } };

const BLACKLISTED = new Set(['seznam.cz','centrum.cz','atlas.cz','volny.cz','tiscali.cz','o2.cz','vodafone.cz','t-mobile.cz','upc.cz','czfree.net','gmail.com','yahoo.com','hotmail.com','outlook.com','protonmail.com','icloud.com','mail.com','zoho.com','aol.com','gmx.com','gmx.net','yandex.com','tutanota.com','live.com','msn.com','post.cz','email.cz','facebook.com','twitter.com','x.com','linkedin.com','instagram.com','youtube.com','tiktok.com','pinterest.com','reddit.com','threads.net','google.com','google.cz','bing.com','duckduckgo.com','wikipedia.org','wikipedie.cz','firmy.cz','kurzy.cz','rejstrik.penize.cz','or.justice.cz','justice.cz','rzp.cz','ares.gov.cz','hbi.cz','detail.cz','databaze-firem.cz','github.com','gitlab.com','medium.com','wordpress.com','blogspot.com','wix.com','squarespace.com','webnode.cz','amazon.com','ebay.com','alibaba.com','aliexpress.com','apple.com','microsoft.com','cloudflare.com','mapy.cz','idnes.cz','novinky.cz','aktualne.cz','heureka.cz','zbozi.cz','slevomat.cz']);
function isBlacklisted(d) { if (!d) return true; if (BLACKLISTED.has(d)) return true; const p = d.split('.'); if (p.length > 2 && BLACKLISTED.has(p.slice(-2).join('.'))) return true; return false; }
const prev = $('Prepare DDG Search').first().json;
const html = ($input.first().json.data || '').toString();

let domain = '';
// Match result links — handle both attribute orderings
const resultPattern = /class="result__a"[^>]*href="([^"]+)"|href="([^"]+)"[^>]*class="result__a"/g;
let match;
while ((match = resultPattern.exec(html)) !== null) {
  const rawUrl = match[1] || match[2];
  if (!rawUrl) continue;
  // DuckDuckGo wraps results in redirect URLs with percent-encoded destination
  let url = rawUrl;
  const uddgMatch = url.match(/[?&]uddg=([^&]+)/);
  if (uddgMatch) {
    try { url = decodeURIComponent(uddgMatch[1]); } catch(e) {}
  }
  if (url.includes('duckduckgo.com')) continue;
  const domainMatch = url.match(/https?:\/\/(?:www\.)?([a-z0-9.-]+\.[a-z]{2,})/i);
  if (domainMatch && domainMatch[1]) {
    const d = domainMatch[1].toLowerCase();
    if (isBlacklisted(d)) continue;
    domain = d;
    break;
  }
}

if (!domain) {
  return [{ json: { lead_id: prev.lead_id, company_id: prev.company_id, company_name: prev.company_name, ico: prev.ico, found: false, domain: '', source: '' } }];
}

return [{ json: { lead_id: prev.lead_id, company_id: prev.company_id, company_name: prev.company_name, ico: prev.ico, found: true, domain: domain, source: 'ddg' } }];
